import { useState, useEffect } from "react";
import "./styles/global.css";

// Pages
import HomePage from "./pages/HomePage";
import RecipeDetailPage from "./pages/RecipeDetailPage";

// Auth
import LoginPage from "./pages/auth/LoginPage";
import RegisterPage from "./pages/auth/RegisterPage";
import ForgotPasswordPage from "./pages/auth/ForgotPasswordPage";

// User
import UserDashboardPage from "./pages/user/UserDashboardPage";

// Chef
import ChefDashboardPage from "./pages/chef/ChefDashboardPage";

// Admin
import AdminDashboardPage from "./pages/admin/AdminDashboardPage";

// Components
import Navbar from "./components/Navbar";

/**
 * RecipeNest — Full Multi-Role App
 *
 * Pages:
 *  "home"             → Public landing + recipe grid
 *  "recipe-detail"    → Single recipe view
 *  "login"            → Login (routes to role dashboard on submit)
 *  "signup"           → Register (role picker: user / chef)
 *  "forgot-password"  → 4-step password reset flow
 *  "user-dashboard"   → Saved recipes, favorites
 *  "chef-dashboard"   → My creations, analytics
 *  "admin-dashboard"  → User mgmt, recipes, analytics, reports
 */
export default function App() {
  const [page, setPage] = useState("home");
  const [history, setHistory] = useState([]);
  const [selectedRecipe, setSelectedRecipe] = useState(null);
  const [user, setUser] = useState(null);
  const [search, setSearch] = useState("");

  // Custom navigation that tracks history
  const navigateTo = (nextPage) => {
    if (nextPage !== page) {
      setHistory(prev => [...prev, page]);
      setPage(nextPage);
    }
  };

  const handleBack = () => {
    if (history.length > 0) {
      const prevPage = history[history.length - 1];
      setHistory(prev => prev.slice(0, -1));
      setPage(prevPage);
    } else {
      setPage("home");
    }
  };

  // Check for stored token on app load
  useEffect(() => {
    const token = localStorage.getItem("token");
    const storedUser = localStorage.getItem("user");

    if (token && storedUser) {
      try {
        setUser(JSON.parse(storedUser));
      } catch (error) {
        console.error("Error parsing stored user:", error);
        localStorage.removeItem("token");
        localStorage.removeItem("user");
      }
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    setUser(null);
    navigateTo("home");
  };

  const isAuthPage = ["login", "signup", "forgot-password"].includes(page);

  return (
    <>
      {/* Background/Main Content */}
      {(page === "home" || isAuthPage) && (
        <>
          <Navbar setPage={navigateTo} user={user} onLogout={handleLogout} onBack={handleBack} showBack={history.length > 0} search={search} setSearch={setSearch} />
          <HomePage setPage={navigateTo} setSelectedRecipe={setSelectedRecipe} search={search} setSearch={setSearch} />
        </>
      )}

      {page === "recipe-detail" && (
        <>
          <Navbar setPage={navigateTo} user={user} onLogout={handleLogout} onBack={handleBack} showBack={true} search={search} setSearch={setSearch} />
          <RecipeDetailPage recipe={selectedRecipe} setPage={navigateTo} onBack={handleBack} />
        </>
      )}

      {page === "user-dashboard" && (user?.role === "user" ? 
        <UserDashboardPage setPage={navigateTo} setSelectedRecipe={setSelectedRecipe} user={user} /> : navigateTo("login"))}

      {page === "chef-dashboard" && (user?.role === "chef" ? 
        <ChefDashboardPage setPage={navigateTo} setSelectedRecipe={setSelectedRecipe} user={user} /> : navigateTo("login"))}

      {page === "admin-dashboard" && (user?.role === "admin" ? 
        <AdminDashboardPage setPage={navigateTo} user={user} /> : navigateTo("login"))}

      {/* Auth Modals (drawn on top) */}
      {page === "login" && <LoginPage setPage={navigateTo} setUser={setUser} onBack={handleBack} />}
      {page === "signup" && <RegisterPage setPage={navigateTo} onBack={handleBack} />}
      {page === "forgot-password" && <ForgotPasswordPage setPage={navigateTo} onBack={handleBack} />}
    </>
  );
}
